        tri.frequency.exponentialRampToValueAtTime(600, now2 + 0.38);
        tg.gain.setValueAtTime(1e-4, now2);
        tg.gain.linearRampToValueAtTime(0.16, now2 + 0.06);
        tg.gain.exponentialRampToValueAtTime(1e-3, now2 + 0.4);
        tri.connect(tg);
        tg.connect(out);
