function rollRarityBand(tier) {
  const r2 = Math.random();
  switch (tier) {
    case 1:
      return r2 < 0.65 ? "common" : r2 < 0.9 ? "uncommon" : r2 < 0.99 ? "rare" : "epic";
    case 2:
      return r2 < 0.55 ? "common" : r2 < 0.83 ? "uncommon" : r2 < 0.97 ? "rare" : "epic";
    case 3:
      return r2 < 0.4 ? "common" : r2 < 0.7 ? "uncommon" : r2 < 0.92 ? "rare" : "epic";
    case 4:
      return r2 < 0.3 ? "common" : r2 < 0.6 ? "uncommon" : r2 < 0.88 ? "rare" : "epic";
  }
}
