function pickFromPool(pool) {
  const entry = pool[Math.floor(Math.random() * pool.length)];
  return {
    itemType: entry.itemType,
    amount: entry.amount[0] + Math.floor(Math.random() * (entry.amount[1] - entry.amount[0] + 1))
  };
}
