  const bodyColor = hitFlash ? "#886060" : "#1a1218";
  const wingColor = hitFlash ? "#704040" : "#0e0a0e";
  const wingTip = hitFlash ? "#603030" : "#160e14";
  const bx = px + TILE_SIZE / 2;
  const by = py + TILE_SIZE / 2 - 2 + bob;
